def process(list, index, value):
    if list is None:
        list = []
    result = list.copy() if hasattr(list, 'copy') else list[:]
    try:
        idx = int(index) if index is not None else 0
        while len(result) <= idx:
            result.append(None)
        result[idx] = value
    except (IndexError, TypeError):
        pass
    return result
